import jakarta.servlet.*;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import org.springframework.stereotype.Component;
import org.springframework.web.filter.OncePerRequestFilter;
import java.io.IOException;

@Component
public class SessionFixationPreventionFilter extends OncePerRequestFilter {

    @Override
    protected void doFilterInternal(
            HttpServletRequest request,
            HttpServletResponse response,
            FilterChain filterChain
    ) throws ServletException, IOException {

        String sessionIdParam = request.getParameter("jsessionid");
        String sessionIdParam2 = request.getParameter("JSESSIONID");
        String sessionIdParam3 = request.getParameter("sessionid");

        if (sessionIdParam != null || sessionIdParam2 != null || sessionIdParam3 != null) {
            logger.warn(String.format(
                "Session fixation attempt detected from IP: %s, URL: %s",
                request.getRemoteAddr(),
                request.getRequestURL()
            ));

            response.setStatus(HttpServletResponse.SC_BAD_REQUEST);
            response.setContentType("application/json");
            response.getWriter().write(
                "{\"error\":\"Invalid request\"," +
                "\"message\":\"Session identifiers in URL are not permitted\"}"
            );
            return;
        }

        filterChain.doFilter(request, response);
    }
}

