const express = require('express');
const session = require('express-session');
const crypto = require('crypto');
const app = express();

function generateClientFingerprint(req) {
  const ipAddress = req.ip || req.connection.remoteAddress;
  const userAgent = req.headers['user-agent'] || '';

  const fingerprint = crypto
    .createHash('sha256')
    .update(ipAddress + userAgent)
    .digest('hex');

  return fingerprint;
}

app.use(session({
  secret: process.env.SESSION_SECRET,
  name: 'sessionId',
  resave: false,
  saveUninitialized: false,
  cookie: {
    secure: true,
    httpOnly: true,
    sameSite: 'strict',
    maxAge: 1800000
  }
}));

app.use((req, res, next) => {
  if (req.path === '/login' || req.path.startsWith('/public')) {
    return next();
  }

  if (req.session && req.session.userId) {
    const currentFingerprint = generateClientFingerprint(req);

    if (req.session.fingerprint !== currentFingerprint) {
      console.warn('Session fingerprint mismatch:', {
        userId: req.session.userId,
        sessionId: req.sessionID,
        originalIP: req.session.ipAddress,
        currentIP: req.ip,
        timestamp: new Date().toISOString()
      });

      req.session.destroy();
      return res.status(401).json({ 
        error: 'Session validation failed',
        message: 'Please log in again'
      });
    }

    req.session.lastActivity = Date.now();
  }

  next();
});

app.post('/login', async (req, res) => {
  const { username, password } = req.body;

  try {
    const user = await authenticateUser(username, password);

    if (!user) {
      return res.status(401).json({ error: 'Invalid credentials' });
    }

    req.session.regenerate((err) => {
      if (err) {
        return res.status(500).json({ error: 'Authentication failed' });
      }

      req.session.userId = user.id;
      req.session.username = user.username;
      req.session.role = user.role;
      req.session.authenticatedAt = Date.now();
      req.session.lastActivity = Date.now();
      req.session.fingerprint = generateClientFingerprint(req);
      req.session.ipAddress = req.ip || req.connection.remoteAddress;
      req.session.userAgent = req.headers['user-agent'];

      req.session.save((err) => {
        if (err) {
          return res.status(500).json({ error: 'Authentication failed' });
        }
        res.json({ success: true, user: { username: user.username, role: user.role } });
      });
    });
  } catch (error) {
    console.error('Login error:', error);
    res.status(500).json({ error: 'Internal server error' });
  }
});

